    "perumal_name": "Sundararaja Perumal (Vadivazhagiya Nambi)",
    "perumal_name_ta": "சுந்தரராஜ பெருமாள் (வடிவழகிய நம்பி)",
    "perumal_name_sa": "Sundararaja",
    "thayar_name": "Sundaravalli Thayar (Azhagiya Valli Nachiyar)",
    "thayar_name_ta": "சுந்தரவல்லி தாயார் (அழகிய வல்லி நாச்சியார்)",
    "posture": "Reclining (Bhujanga Sayanam)",
