    "thayar_name_ta": "உஜ்ஜீவன தாயார் (உய்யவந்த நாச்சியார்)",
    "posture": "Reclining (Bhujanga Sayanam)",
    "facing": "East",
    "facing_ta": "கிழக்கு நோக்கி",
    "vimana": "Sarva Puranika Vimana",
    "vimana_ta": "ஸர்வ புராணிக விமானம்",
    "pushkarini": "Satyagiri Pushkarini",
    "pushkarini_ta": "சத்யகிரி புஷ்கரிணி",
    "town": "Thirumeyyam",
    "town_ta": "திருமெய்யம்",
